import React from "react";
import styles from "./button-add.module.css";
import { useDispatch } from "react-redux";
import { addItem } from "../../app/cartSlice";

interface ButtonAddProps {
    imgSrc: string;
    text: string;
    id: number; // Add id prop for the product
    title: string; // Add title prop for the product
    price: number; // Add price prop for the product

}

const ButtonAdd: React.FC<ButtonAddProps> = ({ imgSrc, text, id, title, price }) => {

  const dispatch = useDispatch();

  const handleAddToCart = () => {
    // Dispatch the addItem action with product details
    dispatch(addItem({ id, imgSrc, title, price }));
  };

  return (
    <button className={styles.button_add} onClick={handleAddToCart}>
      <img src={imgSrc} alt="cart-logo" width={24} height={24} />
      <span className={styles.button_text}>{text}</span>
    </button>
  );
};

export default ButtonAdd;
